<?php namespace App\Services\Audit; use App\Models\Audit\AuditLog; class AuditService { public function log($userId, $action, $entity, $entityId, $before, $after, $overrideReason = null) { AuditLog::create(['user_id' => $userId, 'user_email' => auth()->user()?->email, 'action_type' => $action, 'entity' => $entity, 'entity_id' => $entityId, 'before_snapshot' => $before, 'after_snapshot' => $after, 'ip_address' => request()->ip(), 'user_agent' => request()->userAgent(), 'override_reason' => $overrideReason]); } }
